protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's indexing policy,
    // not EF Core. In EF Core 9 this call throws InvalidOperationException at startup.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name for compatibility with existing documents.
    // EF Core 9 defaults to "$type"; our 500K existing documents and SQL queries use "Discriminator".
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123") so existing documents remain accessible.
    // EF Core 9 defaults to key-only ids (e.g. "123").
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

